# Simulate a PreToolUse event for a dangerous rm command
echo '{
  "hook_event_name": "PreToolUse",
  "session_id": "test-session",
  "tool_name": "Bash",
  "tool_input": { "command": "rm -rf /tmp/build" }
}' | bash .claude/hooks/guard-rm.sh
echo "Exit: $?"

{
  "hookSpecificOutput": {
    "hookEventName": "PreToolUse",
    "permissionDecision": "deny",
    "permissionDecisionReason": "This command pattern is blocked by project policy."
  }
}

{
  "hookSpecificOutput": {
    "hookEventName": "UserPromptSubmit",
    "additionalContext": "Current branch: feature/auth\nModified files: src/auth.ts, tests/auth.test.ts\nOpen ticket: AUTH-1234"
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Is this Bash command destructive, does it modify system state outside the project directory, or does it install global packages? Answer yes or no.",
            "timeout": 20
          }
        ]
      }
    ]
  }
}

{
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          {
            "type": "command",
            "command": "bash -c 'echo \"$CLAUDE_FILE_PATHS\" | tr \" \" \"\\n\" | grep -E \"\\.tsx?$\" | xargs -r npx prettier --write'",
            "async": true
          }
        ]
      }
    ]
  }
}
